  OIDC_ISSUER,
  OIDC_CLIENT_ID,
  OIDC_CLIENT_SECRET,
  OIDC_REDIRECT_URI = `${BASE_URL}/oidc/callback`,
  OIDC_POST_LOGOUT_REDIRECT_URI = `${BASE_URL}/`,
  SESSION_SECRET = crypto.randomBytes(32).toString('hex'),
  SESSION_NAME = 'sid',
