    const claims = jwt.decode(idToken);
    if (!claims || typeof claims !== 'object') return res.status(400).type('text').send('Unable to decode id_token.');

    req.session.user = {
      sub: claims.sub,
      iss: claims.iss,
      aud: claims.aud,
      exp: claims.exp,
      iat: claims.iat,
      nonce: claims.nonce,
      name: claims.name,
      preferred_username: claims.preferred_username,
      email: claims.email,
      email_verified: claims.email_verified,
      given_name: claims.given_name,
      family_name: claims.family_name,
      locale: claims.locale,
      picture: claims.picture,
      ...claims,
    };

